-- =============================================================================
-- Reset demo data for Zeno House - seeded from real Excel data
-- =============================================================================
-- Source files:
--   Cơ sở 1: Dot_01..Dot_06-2026_Nha_Tro_Thanh_Tung.xls
--   Cơ sở 2: Dot_01..Dot_06-2026_Nha_Tro_Thanh_Tung_1.xls
-- Demo period:
--   Previous readings: 2026-05
--   Current workspace: 2026-06
-- Notes:
--   Electricity rate inferred from Excel: 3,500 VND/kWh
--   Water rate inferred from Excel: 14,000 VND/m3
--   Excel column 'Tiền khác' is mapped to contract service 'other'.
-- =============================================================================

BEGIN;

-- -----------------------------------------------------------------------------
-- Required schema guard
-- -----------------------------------------------------------------------------
DO $$
DECLARE
  v_missing text[];
BEGIN
  SELECT array_agg(table_name ORDER BY table_name)
  INTO v_missing
  FROM (
    VALUES ('billing_audit_events'),
      ('invoice_payments'),
      ('invoice_charges'),
      ('invoices'),
      ('billing_utility_usages'),
      ('billing_periods'),
      ('meter_readings'),
      ('contract_services'),
      ('building_services'),
      ('contract_payments'),
      ('contract_renewals'),
      ('contract_occupants'),
      ('contracts'),
      ('rooms'),
      ('tenants'),
      ('buildings'),
      ('service_catalog')
  ) AS required(table_name)
  WHERE to_regclass('public.' || required.table_name) IS NULL;

  IF v_missing IS NOT NULL THEN
    RAISE EXCEPTION
      'Missing required tables: %. Apply the project migrations/manual Supabase SQL before running this seed.',
      array_to_string(v_missing, ', ');
  END IF;
END $$;

-- -----------------------------------------------------------------------------
-- Wipe app data
-- -----------------------------------------------------------------------------
TRUNCATE TABLE
  public.billing_audit_events,
  public.invoice_payments,
  public.invoice_charges,
  public.invoices,
  public.billing_utility_usages,
  public.billing_periods,
  public.meter_readings,
  public.contract_services,
  public.building_services,
  public.contract_payments,
  public.contract_renewals,
  public.contract_occupants,
  public.contracts,
  public.rooms,
  public.tenants,
  public.buildings,
  public.service_catalog
RESTART IDENTITY CASCADE;

